    ('2047126509199200617', 'twitter', 'bunjavascript', 'https://x.com/bunjavascript/status/2047126509199200617', 'Thu Apr 23 01:32:48 +0000 2026', '2026-04-23 13:10:37', NULL, 'In the next version of Bun

